// --- Centralized Constants ---

export const PLACEHOLDER_CHURCH: Church = {
    id: 'unidentified',
    name: '---', 
    address: '',
    logoUrl: '',
    pastor: '',
};

const STOP_WORDS_RESUMO = ['TOTAL', 'SALDO', 'SUBTOTAL', 'RESUMO', 'ACUMULADO', 'FECHAMENTO', 'DISPONIVEL', 'APLICAÇÃO', 'RESGATE', 'SALDO ANTERIOR', 'TOTAL GERAL'];

// --- Specialized Formatting (Isolated Adjustments) ---

/**
 * Ajustes individuais para descrição de ENTRADAS em relatórios.
 * Alterar aqui NÃO afeta o matching nem o relatório de saídas.
 */
export const formatIncomeDescription = (text: string, ignoreKeywords: string[] = []): string => {
    if (!text) return '';
    let cleaned = text.replace(/PIX Recebido|TED|DOC|<[^>]*>/gi, '');

    // CORREÇÃO: Regex corrigido de \d.3} para \d{3}
    cleaned = cleaned.replace(/\d{3}\.\d{3}\.\d{3}-\d{2}|\*\*\*\.\d{3}\.\d{3}-\*\*/g, '');
    cleaned = cleaned.replace(/\b\d{8,}\b/g, '');

    if (ignoreKeywords.length > 0) {
        // Escapa caracteres especiais para o Regex não quebrar
        const pattern = ignoreKeywords
            .filter(k => k.trim().length > 0)
            .map(k => k.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
            .join('|');

        if (pattern) {
            const regex = new RegExp(`\\b(${pattern})\\b`, 'gi');
            cleaned = cleaned.replace(regex, '');
        }
    }

    return cleaned.replace(/\s+/g, ' ').trim();
};

/**
 * Alias para formatIncomeDescription para exibição limpa de descrições.
 */
export const cleanTransactionDescriptionForDisplay = formatIncomeDescription;

/**
 * Ajustes individuais para descrição de SAÍDAS em relatórios.
 */
export const formatExpenseDescription = (text: string): string => {
    if (!text) return '';
    let cleaned = text.replace(/PAGAMENTO|DÉBITO|DOC\/TED|CANAL/gi, '');
    return cleaned.replace(/\s+/g, ' ').trim();
};

// --- Core Matching Logic ---

export const normalizeString = (str: string, ignoreKeywords: string[] = []): string => {
    if (!str) return '';
    let normalized = str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    normalized = normalized.replace(/\d{3}\.\d{3}\.\d{3}-\d{2}|\*\*\*\.\d{3}\.\d{3}-\*\*/g, '');
    normalized = normalized.replace(/\b\d{8,}\b/g, '');

    if (ignoreKeywords.length > 0) {
        const pattern = ignoreKeywords
            .filter(k => k.trim().length > 0)
            .map(k => k.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&'))
            .join('|');
        if (pattern) {
            const regex = new RegExp(`\\b(${pattern})\\b`, 'gi');
            normalized = normalized.replace(regex, '');
        }
    }

    return normalized.replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
};

export const calculateNameSimilarity = (desc: string, contrib: Contributor): number => {
    const s1 = normalizeString(desc);
    const s2 = contrib.normalizedName || normalizeString(contrib.name);
    if (!s1 || !s2) return 0;

    const words1 = new Set(s1.split(' ').filter(w => w.length > 1));
    const words2 = new Set(s2.split(' ').filter(w => w.length > 1));

    const intersect = new Set([...words1].filter(w => words2.has(w)));
    return (2 * intersect.size) / (words1.size + words2.size) * 100;
};

// --- Parsers & Search ---

export const parseDate = (dateString: string, defaultYear?: number | null): Date | null => {
    if (!dateString || typeof dateString !== 'string') return null;
    const trimmed = dateString.trim().replace(/^['"]|['"]$/g, '');

    // Uma data válida para nós DEVE ter um separador (barra, traço ou ponto)
    if (!/[/\-.]/.test(trimmed)) return null;

    const parts = trimmed.match(/(\d+)/g);
    if (!parts || parts.length < 2) return null;

    let day, month, year;
    if (parts.length === 2) {
        day = parseInt(parts[0], 10);
        month = parseInt(parts[1], 10);
        year = defaultYear || new Date().getFullYear();
    } else {
        if (parts[0].length === 4) { [year, month, day] = parts.map(p => parseInt(p, 10)); }
        else { 
            [day, month, year] = parts.map(p => parseInt(p, 10)); 
            if (String(year).length === 2) year += (year < 50 ? 2000 : 1900); 
        }
    }

    if (month > 12 || day > 31) return null;

    const date = new Date(Date.UTC(year, month - 1, day));
    return (!isNaN(date.getTime())) ? date : null;
};

const isDateString = (s: string): boolean => !!s && parseDate(s) !== null;

const isAmountString = (s: string): boolean => {
    if (!s || typeof s !== 'string') return false;
    const clean = s.trim().replace(/[R$\s]/g, '');
    if (!/\d/.test(clean)) return false;
    // Se parece uma data, não é um valor
    if (isDateString(s)) return false;
    const val = parseAmountString(clean);
    return !isNaN(val); 
};

/**
 * Interpretador de valores monetários ajustado para o erro "8.100 -> 8,00"
 */
const parseAmountString = (s: string): number => {
    if (!s) return 0;
    if (typeof s === 'number') return s;

    let cleanS = s.toString().trim().replace(/[R$BRL\s]/gi, '');
    let isNegative = s.includes('-') || s.includes('(') || /\b(D|Db|Dr|Débito)\b/i.test(s);

    // Lógica Brasileira:
    // 8.100,00 -> 8100.00
    // 1.234,56 -> 1234.56
    if (cleanS.includes(',') && cleanS.includes('.')) {
        cleanS = cleanS.replace(/\./g, '').replace(',', '.');
    } else if (cleanS.includes(',')) {
        // Apenas vírgula: assume que é o decimal (ex: 100,00 ou 8100,00)
        cleanS = cleanS.replace(',', '.');
    } else if (cleanS.includes('.')) {
        // Apenas ponto: Se tiver 3 casas após o ponto, em arquivos BR de bancos, costuma ser milhar (8.100)
        const parts = cleanS.split('.');
        const lastPart = parts[parts.length - 1];
        if (parts.length > 2 || (parts.length === 2 && lastPart.length === 3)) {
            cleanS = cleanS.replace(/\./g, '');
        }
    }

    const value = parseFloat(cleanS.replace(/[^\d.-]/g, ''));
    return isNegative ? -Math.abs(value) : Math.abs(value);
};

/**
 * Divide linhas respeitando aspas e tratando o delimitador vírgula com cautela.
 */
const splitCSVLine = (line: string, delimiter: string): string[] => {
    const result: string[] = [];
    let curVal = "";
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
        const char = line[i];
        if (char === '"') {
            inQuotes = !inQuotes;
        } else if (char === delimiter && !inQuotes) {
            result.push(curVal.trim());
            curVal = "";
        } else {
            curVal += char;
        }
    }
    result.push(curVal.trim());
    return result;
};

const intelligentParser = <T>(content: string, type: 'EXTRATO' | 'LISTA'): T[] => {
    // Detecta delimitador: Prioriza ponto-e-vírgula e tabulação para evitar que a vírgula decimal quebre o arquivo
    let delimiter = ';';
    if (content.includes('\t')) delimiter = '\t';
    else if (!content.includes(';') && content.includes(',')) {
        // Só usa vírgula se não houver ponto-e-vírgula (comum em CSVs americanos, raro em BR)
        delimiter = ',';
    }

    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 1) return [];

    const parsedRows = lines.map(l => splitCSVLine(l, delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));

    // Amostragem para detectar colunas
    const sample = parsedRows.slice(0, 50);
    const numCols = Math.max(...sample.map(l => l.length));
    const colStats = Array.from({ length: numCols }, () => ({ dates: 0, amounts: 0, sumAbsValue: 0 }));

    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (!cell || i >= numCols) return;
            if (isDateString(cell)) colStats[i].dates++;
            // Um valor só conta como "Amount" se não for uma "Date"
            if (!isDateString(cell) && isAmountString(cell)) { 
                colStats[i].amounts++; 
                colStats[i].sumAbsValue += Math.abs(parseAmountString(cell)); 
            }
        });
    });

    // Escolhe a coluna de data (a que tem mais datas válidas)
    let dateIdx = colStats.findIndex((s, i) => s.dates === Math.max(...colStats.map(x => x.dates)) && s.dates > 0);

    // Escolhe a coluna de valor (que não é a data e tem mais números)
    let amountIdx = colStats.findIndex((s, i) => i !== dateIdx && s.amounts === Math.max(...colStats.map((x, idx) => idx === dateIdx ? -1 : x.amounts)) && s.amounts > 0);

    // Texto/Descrição é o que sobrar com mais caracteres
    let textIdx = -1;
    let maxLen = -1;
    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (i !== dateIdx && i !== amountIdx && cell.length > maxLen) {
                maxLen = cell.length;
                textIdx = i;
            }
        });
    });

    const results: any[] = [];
    parsedRows.forEach(row => {
        const dateRaw = dateIdx !== -1 ? row[dateIdx] : null;
        const amountRaw = amountIdx !== -1 ? row[amountIdx] : null;
        const textRaw = textIdx !== -1 ? row[textIdx] : null;

        if (!dateRaw || !amountRaw || !isDateString(dateRaw) || !isAmountString(amountRaw)) return;

        const amount = parseAmountString(amountRaw);

        if (type === 'EXTRATO') {
            results.push({ date: dateRaw, amount: amount, originalAmount: amountRaw, description: textRaw || 'Sem Descrição' });
        } else {
            if (textRaw && textRaw.length > 2) {
                const upperText = textRaw.toUpperCase();
                if (!STOP_WORDS_RESUMO.some(sw => upperText.includes(sw)) && !['NOME', 'CONTRIBUINTE', 'MEMBRO'].includes(upperText)) {
                    results.push({ name: textRaw, date: dateRaw, amount: amount, originalAmount: amountRaw });
                }
            }
        }
    });
    return results;
};

