        if (char === '"') inQuotes = !inQuotes;
        else if (char === delimiter && !inQuotes) {
            result.push(curVal.trim());
            curVal = "";
        } else curVal += char;
    }
    result.push(curVal.trim());
    return result;
};

const intelligentParser = <T>(content: string, type: 'EXTRATO' | 'LISTA'): T[] => {
    let delimiter = ';';
    if (content.includes('\t')) delimiter = '\t';
    else if (!content.includes(';') && content.includes(',')) delimiter = ',';

    const rawLines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (rawLines.length < 1) return [];

    const parsedRows = rawLines.map(l => splitCSVLine(l, delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));
    const sample = parsedRows.slice(0, 50);
    const numCols = Math.max(...sample.map(l => l.length));

    const colStats = Array.from({ length: numCols }, () => ({ 
        dates: 0, 
        amounts: 0, 
        filledRows: 0,
        sumAbs: 0 
    }));

    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (i >= numCols) return;
            if (cell && cell.length > 0) colStats[i].filledRows++;
            if (isDateString(cell)) colStats[i].dates++;
            if (isAmountString(cell)) {
                colStats[i].amounts++;
                colStats[i].sumAbs += Math.abs(parseAmountString(cell));
            }
        });
    });

    let dateIdx = colStats.findIndex((s, i) => s.dates === Math.max(...colStats.map(x => x.dates)) && s.dates > 0);

    // DETECÇÃO DE COLUNA DE TRANSAÇÃO vs SALDO (Density Heuristic)
    const amountCandidates = colStats
        .map((s, i) => ({ 
            i, 
            count: s.amounts, 
            density: s.filledRows / sample.length,
            avg: s.amounts > 0 ? s.sumAbs / s.amounts : 0 
        }))
        .filter(c => c.i !== dateIdx && c.count > 0);

    // Identificamos colunas esparsas (< 90% preenchimento) como candidatas a Transação
    // Colunas densas (> 90%) como provável "Saldo Acumulado" (Balance)
    let transactionAmountIndices: number[] = [];
    if (amountCandidates.length > 1) {
        transactionAmountIndices = amountCandidates
            .filter(c => c.density < 0.90 || amountCandidates.length === 1)
            .map(c => c.i);

        // Se o filtro de densidade falhar (ex: extrato curto), pegamos a coluna com menor média de valores
        // (Saldos são sempre maiores que as transações individuais)
        if (transactionAmountIndices.length === 0) {
            transactionAmountIndices = [amountCandidates.sort((a, b) => a.avg - b.avg)[0].i];
        }
    } else if (amountCandidates.length === 1) {
        transactionAmountIndices = [amountCandidates[0].i];
    }

    let textIdx = -1;
    let maxLen = -1;
    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (i !== dateIdx && !transactionAmountIndices.includes(i) && cell.length > maxLen) {
                maxLen = cell.length;
                textIdx = i;
            }
        });
    });

    const results: any[] = [];
    parsedRows.forEach(row => {
        const dateRaw = dateIdx !== -1 ? row[dateIdx] : null;
        const textRaw = textIdx !== -1 ? row[textIdx] : null;

        if (!dateRaw || !isDateString(dateRaw)) return;

        // Pega o valor da coluna de transação que estiver preenchida (Débito OU Crédito)
        let finalAmount = 0;
        let foundValue = false;
        let rawAmountStr = "";

        for (const idx of transactionAmountIndices) {
            const cellVal = row[idx];
            if (isAmountString(cellVal)) {
                const parsed = parseAmountString(cellVal);
                if (parsed !== 0) {
                    finalAmount = parsed;
                    rawAmountStr = cellVal;
                    foundValue = true;
                    break; 
                }
            }
        }

        if (!foundValue && type === 'EXTRATO') return;

        if (type === 'EXTRATO') {
            results.push({ 
                date: dateRaw, 
                amount: finalAmount, 
                originalAmount: rawAmountStr || '0,00', 
                description: textRaw || 'Sem Descrição' 
            });
        } else {
            if (textRaw && textRaw.length > 2) {
                const upperText = textRaw.toUpperCase();
                if (!STOP_WORDS_RESUMO.some(sw => upperText.includes(sw))) {
                    results.push({ name: textRaw, date: dateRaw, amount: finalAmount, originalAmount: rawAmountStr });
                }
            }
        }
    });
    return results;
};

