        if (char === '"') inQuotes = !inQuotes;
        else if (char === delimiter && !inQuotes) {
            result.push(curVal.trim());
            curVal = "";
        } else curVal += char;
    }
    result.push(curVal.trim());
    return result;
};

const intelligentParser = <T>(content: string, type: 'EXTRATO' | 'LISTA'): T[] => {
    let delimiter = ';';
    if (content.includes('\t')) delimiter = '\t';
    else if (!content.includes(';') && content.includes(',')) delimiter = ',';

    const rawLines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (rawLines.length < 1) return [];

    const parsedRows = rawLines.map(l => splitCSVLine(l, delimiter).map(c => c.replace(/^["']|["']$/g, '').trim()));

    // 1. Identificação de Colunas via Amostragem (Heurística de Peso)
    const sample = parsedRows.slice(0, 40);
    const numCols = Math.max(...sample.map(l => l.length));
    const colScores = Array.from({ length: numCols }, () => ({ dateScore: 0, amountScore: 0, textLen: 0, filled: 0 }));

    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (!cell || i >= numCols) return;
            colScores[i].filled++;
            if (isDateString(cell)) colScores[i].dateScore++;
            if (isAmountString(cell)) colScores[i].amountScore++;
            colScores[i].textLen += cell.length;
        });
    });

    // Encontra o melhor índice de data
    let dateIdx = -1;
    let maxDateScore = 0;
    colScores.forEach((s, i) => {
        if (s.dateScore > maxDateScore) {
            maxDateScore = s.dateScore;
            dateIdx = i;
        }
    });

    // Encontra candidatos a colunas de valor (mais de 10% da amostragem)
    const amountIndices = colScores
        .map((s, i) => ({ i, score: s.amountScore }))
        .filter(c => c.i !== dateIdx && c.score > (sample.length * 0.1))
        .map(c => c.i);

    // Encontra melhor coluna de texto (maior média de caracteres, que não seja data ou valor)
    let textIdx = -1;
    let maxTextScore = -1;
    colScores.forEach((s, i) => {
        if (i === dateIdx || amountIndices.includes(i)) return;
        const avgLen = s.filled > 0 ? s.textLen / s.filled : 0;
        if (avgLen > maxTextScore) {
            maxTextScore = avgLen;
            textIdx = i;
        }
    });

    // Se falhar em achar colunas essenciais para o extrato, aborta com log
    if (type === 'EXTRATO' && (dateIdx === -1 || amountIndices.length === 0)) {
        console.warn("Falha ao detectar colunas essenciais no extrato bancário.");
        return [];
    }

    const results: any[] = [];
    parsedRows.forEach((row, rowIndex) => {
        const dateRaw = dateIdx !== -1 ? row[dateIdx] : null;
        const textRaw = textIdx !== -1 ? row[textIdx] : null;

        // Validação da linha: Deve ter uma data válida
        if (!dateRaw || !isDateString(dateRaw)) return;

        // HEURÍSTICA DE FIDELIDADE: ESCOLHER O MENOR VALOR ABSOLUTO (Pula o Saldo)
        // Ignora números que parecem IDs (inteiros longos sem decimais)
        let chosenAmount = Infinity;
        let originalValueStr = "0,00";
        let foundAnyAmount = false;

        for (const idx of amountIndices) {
            const cellVal = row[idx];
            if (!cellVal) continue;

            const parsed = parseAmountString(cellVal);
            if (parsed === 0) continue;

            const absVal = Math.abs(parsed);

            // Regra Anti-ID: Se o número for muito grande e não tiver vírgula ou ponto no original, 
            // e houver outro número na linha com decimais, preferimos o com decimais.
            const looksLikeID = /^\d{5,}$/.test(cellVal.replace(/[.\-]/g, '')) && !cellVal.includes(',') && !cellVal.includes('.');

            if (absVal < chosenAmount) {
                // Se já tínhamos um valor e o novo parece um ID, ignoramos o novo
                if (foundAnyAmount && looksLikeID) continue;

                chosenAmount = absVal;
                originalValueStr = cellVal;
                foundAnyAmount = true;
            }
        }

        // Se for extrato e não achou valor nenhum, descarta a linha (provavelmente cabeçalho ou rodapé)
        if (type === 'EXTRATO' && !foundAnyAmount) return;

        // Ajuste de sinal: se o escolhido foi negativo, mantém negativo
        const finalValue = parseAmountString(originalValueStr);

        if (type === 'EXTRATO') {
            results.push({ 
                date: dateRaw, 
                amount: finalValue, 
                originalAmount: originalValueStr, 
                description: textRaw || 'Sem Descrição' 
            });
        } else {
            if (textRaw && textRaw.length > 2) {
                const upperText = textRaw.toUpperCase();
                if (!STOP_WORDS_RESUMO.some(sw => upperText.includes(sw))) {
                    results.push({ name: textRaw, date: dateRaw, amount: finalValue, originalAmount: originalValueStr });
                }
            }
        }
    });

    return results;
};

